import '../../../../core/errors/api_exception.dart'; import '../../../../core/errors/failure.dart'; import '../../../../core/errors/network_exception.dart'; import '../../../../core/utils/result.dart'; import '../../domain/models/offer.dart'; import '../../domain/repositories/offer_repository.dart'; import '../datasources/offer_remote_datasource.dart'; import '../mappers/offer_mapper.dart';
final class OfferRepositoryImpl implements OfferRepository { const OfferRepositoryImpl({required OfferRemoteDataSource remoteDataSource, this.mapper = const OfferMapper()}) : _remoteDataSource = remoteDataSource; final OfferRemoteDataSource _remoteDataSource; final OfferMapper mapper;
  @override Future<Result<List<Offer>>> getOffers(String orderId) async { try { final values = await _remoteDataSource.getOffers(orderId); return Success(values.map(mapper.fromDto).toList()); } on Exception catch (error) { return ErrorResult(_failure(error)); } }
  @override Future<Result<Offer>> createOffer(Offer offer) async { try { return Success(mapper.fromDto(await _remoteDataSource.createOffer(mapper.toDto(offer)))); } on Exception catch (error) { return ErrorResult(_failure(error)); } }
  @override Future<Result<Offer>> acceptOffer(String id) async { try { return Success(mapper.fromDto(await _remoteDataSource.acceptOffer(id))); } on Exception catch (error) { return ErrorResult(_failure(error)); } }
  Failure _failure(Exception error) => error is ApiException ? Failure(message: error.message, code: error.code, statusCode: error.statusCode) : error is NetworkException ? Failure(message: error.message) : Failure(message: error.toString()); }
